+type Clause = { kind: 'clause'; patterns?: readonly unknown[]; predicate?: (value: unknown) => unknown; handler: (selection: unknown, value: unknown) => unknown };
+type Tap = { kind: 'tap'; callback: (result: unknown) => unknown };
+type Step = Clause | Tap;
+
+/**
+ * Creates a pattern matcher that evaluates all matching clauses.
+ * When called without a value, it creates a reusable matcher for `.toFunction()`.
+ */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(value?: unknown): MatchEach<any, any> {
+  return new MatchEachExpression([], arguments.length > 0, value) as any;
+}
