+
+  with(...args: any[]) {
+    const handler = args[args.length - 1];
+    let patterns: unknown[] = [args[0]];
+    let predicate: ((value: unknown) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns = args.slice(0, -1);
+    return this.next({ kind: 'clause', patterns, predicate, handler });
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown) {
+    return this.next({ kind: 'clause', predicate, handler });
+  }
+
+  tap(callback: (result: unknown) => unknown) {
+    return this.next({ kind: 'tap', callback });
+  }
+
+  otherwise(handler: (value: unknown) => unknown) {
+    const results = this.evaluateInput();
+    return results.length ? results : [handler(this.input)];
